    {"id": "group-relative-policy-optimization", "name": "Group Relative Policy Optimization", "aliases": ["GRPO", "RLVR", "RL with verifiable rewards", "reasoning RL"], "category": "reinforcement-learning", "tier": "frontier", "definition": "A critic-free policy-gradient variant that estimates advantages by normalizing rewards across a group of sampled completions for the same prompt, eliminating the value network used by PPO. Popularized by DeepSeek for training reasoning LLMs, it is central to RL-with-verifiable-rewards (RLVR) for math and code.", "prereqs": ["proximal-policy-optimization", "rlhf", "policy-gradient-methods"], "related": ["rlhf", "proximal-policy-optimization", "chain-of-thought", "test-time-compute"]},
    {"id": "multi-agent-rl", "name": "Multi-Agent Reinforcement Learning", "aliases": ["MARL", "multi-agent RL", "self-play", "Nash equilibrium learning", "CTDE", "game theory"], "category": "reinforcement-learning", "tier": "frontier", "definition": "RL in environments with multiple simultaneously-learning agents, where the environment is non-stationary from any single agent's view and equilibrium/game-theoretic solution concepts replace single-agent optimality. Techniques include self-play, centralized-training-decentralized-execution (CTDE), and population-based training, powering systems like AlphaStar and emergent multi-agent tool use.", "prereqs": ["policy-gradient-methods", "markov-decision-process", "exploration-exploitation"], "related": ["actor-critic", "monte-carlo-tree-search", "tool-use-agents"]},
    {"id": "rlhf", "name": "RL from Human/AI Feedback (RLHF)", "aliases": ["RLHF", "RLAIF", "reinforcement learning from human feedback", "preference optimization", "preference tuning"], "category": "reinforcement-learning", "tier": "frontier", "definition": "A pipeline that aligns generative models by training a reward model from human (or AI) preference comparisons and then optimizing the policy against it with RL (typically PPO), or via direct preference methods (DPO) that skip the explicit RL loop. It is the dominant technique for instruction-following and safety alignment of large language models, with GRPO emerging for reasoning models.", "prereqs": ["proximal-policy-optimization", "reward-model", "instruction-tuning"], "related": ["group-relative-policy-optimization", "dpo", "reward-model", "reward-hacking", "constitutional-ai"]},
    {"id": "image-classification", "name": "Image Classification", "aliases": ["ImageNet classification", "image recognition", "ImageNet"], "category": "vision-multimodal", "tier": "foundational", "definition": "The task of assigning one or more category labels to an entire image, classically benchmarked on ImageNet, learned by mapping pixel inputs through a backbone to a softmax over classes. It is the canonical supervised vision task on which transfer-learning backbones and architectural advances are first validated.", "prereqs": ["convolutional-neural-network", "supervised-learning", "activation-function"], "related": ["object-detection", "vision-transformer", "fine-tuning"]},
    {"id": "image-segmentation", "name": "Image Segmentation", "aliases": ["semantic segmentation", "instance segmentation", "panoptic segmentation", "SAM", "Segment Anything"], "category": "vision-multimodal", "tier": "intermediate", "definition": "The task of assigning a label to each pixel, spanning semantic (per-class), instance (per-object), and panoptic (unified) variants. Promptable foundation models like Segment Anything (SAM/SAM 2) produce masks from point, box, or text prompts and generalize zero-shot across domains and video.", "prereqs": ["object-detection", "convolutional-neural-network"], "related": ["object-detection", "self-supervised-vision", "vision-foundation-models"]},
    {"id": "object-detection", "name": "Object Detection", "aliases": ["bounding box detection", "YOLO", "DETR", "Faster R-CNN", "Grounding DINO"], "category": "vision-multimodal", "tier": "intermediate", "definition": "The task of localizing and classifying multiple objects in an image by predicting bounding boxes plus class labels, via one-stage (YOLO, RetinaNet), two-stage (Faster R-CNN), or set-prediction transformer (DETR) approaches. Open-vocabulary detectors (e.g. Grounding DINO) extend this to arbitrary text-specified categories.", "prereqs": ["image-classification", "convolutional-neural-network"], "related": ["image-segmentation", "vision-language-models", "vision-transformer"]},
    {"id": "ocr-document-ai", "name": "OCR & Document Understanding", "aliases": ["OCR", "optical character recognition", "document AI", "DocVQA", "layout understanding"], "category": "vision-multimodal", "tier": "intermediate", "definition": "Extracting and interpreting text and structure from images of documents, encompassing character recognition, layout/table parsing, and document visual question answering. Modern approaches are increasingly OCR-free, using vision-language models that read pixels end-to-end to answer questions over forms, charts, and scanned pages.", "prereqs": ["image-classification", "vision-language-models"], "related": ["vision-language-models", "visual-grounding", "vision-transformer"]},
    {"id": "pose-estimation", "name": "Pose Estimation", "aliases": ["human pose estimation", "keypoint detection", "2D/3D pose", "OpenPose", "ViTPose"], "category": "vision-multimodal", "tier": "intermediate", "definition": "Localizing the keypoints (joints/landmarks) of a person or object to recover its 2D or 3D articulated configuration, via heatmap regression or transformer-based keypoint prediction. It underpins motion capture, action recognition, AR/VR, and robotics, and increasingly supports multi-person and 3D mesh recovery.", "prereqs": ["object-detection", "convolutional-neural-network"], "related": ["object-detection", "vision-transformer", "neural-radiance-fields"]},
    {"id": "vision-transformer", "name": "Vision Transformer", "aliases": ["ViT", "DeiT", "Swin Transformer", "image transformer"], "category": "vision-multimodal", "tier": "intermediate", "definition": "An architecture that splits an image into fixed-size patches, linearly embeds them as tokens, and processes the sequence with a standard transformer encoder using self-attention instead of convolution. ViTs match or exceed CNNs given sufficient data/pretraining and underpin most modern vision and multimodal backbones.", "prereqs": ["transformer-architecture", "attention-mechanism", "image-classification"], "related": ["self-supervised-vision", "clip", "vision-language-models", "convolutional-neural-network"]},
    {"id": "clip", "name": "CLIP (Contrastive Language-Image Pretraining)", "aliases": ["CLIP", "contrastive language-image pretraining", "SigLIP", "OpenCLIP"], "category": "vision-multimodal", "tier": "advanced", "definition": "A dual-encoder model that jointly trains an image encoder and a text encoder with a contrastive loss over large image-caption pairs, producing a shared embedding space that enables zero-shot classification and retrieval. CLIP-style encoders (and successors like SigLIP) are the standard vision frontends for most vision-language models and text-to-image generators.", "prereqs": ["contrastive-learning", "vision-transformer", "embeddings"], "related": ["vision-language-models", "multimodal-fusion", "text-to-image-generation"]},
    {"id": "contrastive-learning", "name": "Contrastive Learning", "aliases": ["SimCLR", "MoCo", "InfoNCE", "contrastive representation learning"], "category": "vision-multimodal", "tier": "advanced", "definition": "A representation-learning paradigm that pulls embeddings of matching (positive) pairs together and pushes non-matching (negative) pairs apart, typically via the InfoNCE loss over augmented views or cross-modal pairs. It is the core training signal behind SimCLR/MoCo for vision and CLIP for vision-language alignment.", "prereqs": ["self-supervised-learning", "embeddings"], "related": ["self-supervised-vision", "clip", "multimodal-fusion"]},
    {"id": "multimodal-fusion", "name": "Multimodal Fusion", "aliases": ["modality fusion", "cross-attention fusion", "early/late fusion", "Q-Former", "projector"], "category": "vision-multimodal", "tier": "advanced", "definition": "The set of techniques for combining representations from different modalities (e.g. vision, text, audio) into a joint model, including early/late fusion, cross-attention, and learned connectors/adapters (projectors, Q-Former) that map visual features into a language model's token space. Fusion strategy and alignment quality largely determine a multimodal model's grounding and reasoning ability.", "prereqs": ["clip", "attention-mechanism", "embeddings"], "related": ["vision-language-models", "clip", "contrastive-learning"]},
    {"id": "self-supervised-vision", "name": "Self-Supervised Vision Learning", "aliases": ["SSL vision", "DINO", "DINOv2", "MAE", "masked autoencoder", "BYOL"], "category": "vision-multimodal", "tier": "advanced", "definition": "Learning visual representations from unlabeled images via pretext objectives such as masked image modeling (MAE) or self-distillation between augmented views (DINO/DINOv2), producing transferable features without human labels. These methods yield strong frozen backbones for detection, segmentation, and dense prediction.", "prereqs": ["vision-transformer", "self-supervised-learning", "contrastive-learning"], "related": ["contrastive-learning", "vision-foundation-models", "image-segmentation"]},
    {"id": "visual-grounding", "name": "Visual Grounding & Referring", "aliases": ["grounding", "referring expression", "phrase grounding", "open-vocabulary"], "category": "vision-multimodal", "tier": "advanced", "definition": "The task of localizing the image region (box, mask, or point) referred to by a natural-language phrase, linking language tokens to specific visual content. Grounding underpins open-vocabulary detection/segmentation and the spatial-pointing abilities of agentic vision-language models.", "prereqs": ["object-detection", "vision-language-models"], "related": ["object-detection", "image-segmentation", "vision-language-models"]},
    {"id": "neural-radiance-fields", "name": "Neural Radiance Fields & 3D Reconstruction", "aliases": ["NeRF", "3D Gaussian Splatting", "3DGS", "novel view synthesis", "neural rendering"], "category": "vision-multimodal", "tier": "frontier", "definition": "Representations that reconstruct a 3D scene from posed 2D images for novel-view synthesis, either as a continuous volumetric MLP queried by ray marching (NeRF) or as an explicit set of optimized 3D Gaussians rendered by differentiable rasterization (3D Gaussian Splatting). They enable photorealistic free-viewpoint rendering and feed text-to-3D and embodied/simulation pipelines.", "prereqs": ["neural-network", "multilayer-perceptron"], "related": ["text-to-video-generation", "text-to-image-generation", "world-models"]},
    {"id": "text-to-image-generation", "name": "Text-to-Image Generation", "aliases": ["text-to-image", "Stable Diffusion", "DALL-E", "Midjourney", "Imagen", "FLUX", "DiT"], "category": "vision-multimodal", "tier": "frontier", "definition": "Generating images from text prompts, dominated by latent diffusion models that iteratively denoise in a learned latent space conditioned on text embeddings, with rectified-flow and DiT (diffusion transformer) backbones in recent systems. Production models (Stable Diffusion, DALL-E, Imagen, FLUX) add classifier-free guidance and CLIP/T5 text conditioning for prompt adherence.", "prereqs": ["diffusion-models", "clip", "vision-transformer"], "related": ["text-to-video-generation", "clip", "neural-radiance-fields"]},
    {"id": "text-to-video-generation", "name": "Text-to-Video Generation", "aliases": ["text-to-video", "Sora", "Veo", "Kling", "Runway", "video diffusion"], "category": "vision-multimodal", "tier": "frontier", "definition": "Generating temporally coherent video from text (and/or image) prompts using spatiotemporal diffusion transformers operating on compressed video latents, with attention or 3D convolutions enforcing motion consistency. Frontier systems (Sora, Veo, Kling, Runway) push toward longer, physically plausible clips and are increasingly framed as learned world simulators.", "prereqs": ["text-to-image-generation", "diffusion-models", "vision-transformer"], "related": ["text-to-image-generation", "world-models", "neural-radiance-fields"]},
    {"id": "vision-foundation-models", "name": "Vision Foundation Models", "aliases": ["vision foundation model", "VFM", "promptable vision model", "DINOv2", "SAM"], "category": "vision-multimodal", "tier": "frontier", "definition": "Large vision models pretrained at scale to serve as general-purpose backbones or promptable systems transferable across many tasks with little or no fine-tuning (e.g. DINOv2 features, SAM segmentation, CLIP alignment). They shift vision from task-specific training toward reusable, zero-shot, foundation-style capabilities.", "prereqs": ["self-supervised-vision", "vision-transformer", "clip"], "related": ["self-supervised-vision", "image-segmentation", "vision-language-models"]},
    {"id": "vision-language-models", "name": "Vision-Language & Multimodal Models", "aliases": ["VLM", "multimodal LLM", "MLLM", "multimodal models", "LLaVA", "Qwen-VL", "GPT-4V", "Gemini"], "category": "vision-multimodal", "tier": "frontier", "definition": "Models that condition a large language model on visual inputs (images, often video) by projecting visual encoder features into the LLM's token space, enabling captioning, visual question answering, document/chart understanding, and grounded reasoning. Modern VLMs (LLaVA, Qwen-VL, GPT-4V/o-series, Gemini) are trained with visual instruction tuning and increasingly support interleaved image-text and agentic use.", "prereqs": ["multimodal-fusion", "clip", "large-language-models", "instruction-tuning"], "related": ["multimodal-fusion", "clip", "ocr-document-ai", "visual-grounding"]},
    {"id": "world-models", "name": "World Models", "aliases": ["world model", "learned world simulator", "neural simulator", "world simulation"], "category": "vision-multimodal", "tier": "frontier", "definition": "Learned generative models of an environment's dynamics that predict how observations evolve under actions or over time, used for planning, imagination-based training, and as a framing for video generators that implicitly learn physics. They bridge generative modeling, model-based RL, and embodied agents.", "prereqs": ["model-based-rl", "diffusion-models"], "related": ["model-based-rl", "text-to-video-generation", "active-inference", "embodied-cognition"]},
    {"id": "attention-salience", "name": "Attention and Salience", "aliases": ["attention", "salience", "saliency map", "selective attention"], "category": "cognitive-architectures", "tier": "foundational", "definition": "The cognitive mechanisms that selectively prioritize a subset of available information for processing, driven by bottom-up salience (stimulus conspicuity) and top-down goals. As a cognitive construct it predates and motivates the attention mechanisms central to modern neural architectures.", "prereqs": ["working-memory"], "related": ["attention-mechanism", "global-workspace-theory", "hierarchical-control"]},
    {"id": "cognitive-architecture", "name": "Cognitive Architecture", "aliases": ["cognitive architectures", "unified theory of cognition"], "category": "cognitive-architectures", "tier": "foundational", "definition": "A fixed computational framework specifying the structures and mechanisms (memory stores, learning rules, control flow) hypothesized to be invariant across all cognition, into which task-specific knowledge is loaded to model or produce intelligent behavior. It aims at a unified theory of cognition rather than a single-task model.", "prereqs": [], "related": ["act-r", "soar", "production-systems", "working-memory", "neuro-symbolic-ai"]},
    {"id": "dual-process-theory", "name": "Dual-Process Theory", "aliases": ["System 1 System 2", "dual process", "fast and slow thinking", "Type 1 Type 2"], "category": "cognitive-architectures", "tier": "foundational", "definition": "The proposal that cognition involves two kinds of processing: fast, automatic, parallel, intuitive 'System 1' and slow, effortful, serial, deliberative 'System 2'. It is heavily invoked in current LLM research to frame the gap between pattern-matching generation and explicit reasoning (e.g., chain-of-thought and test-time deliberation).", "prereqs": [], "related": ["metacognition", "chain-of-thought", "clarion", "test-time-compute"]},
    {"id": "production-systems", "name": "Production Systems", "aliases": ["production rules", "rule-based systems", "if-then rules"], "category": "cognitive-architectures", "tier": "foundational", "definition": "A computational model of behavior consisting of a working memory and a set of condition-action ('if-then') production rules, where a recognize-act cycle repeatedly matches rule conditions against memory and fires applicable rules to modify state. It is the core inference engine underlying many symbolic cognitive architectures.", "prereqs": ["cognitive-architecture"], "related": ["act-r", "soar", "working-memory", "blackboard-systems"]},
    {"id": "working-memory", "name": "Working Memory Models", "aliases": ["working memory", "Baddeley model", "central executive"], "category": "cognitive-architectures", "tier": "foundational", "definition": "Cognitive models of the limited-capacity system that temporarily holds and manipulates information in service of ongoing tasks (e.g., Baddeley-Hitch's phonological loop, visuospatial sketchpad, episodic buffer, and central executive). It is a core construct that constrains buffers and attention mechanisms in cognitive architectures and inspires memory components in AI agents.", "prereqs": [], "related": ["attention-salience", "act-r", "declarative-procedural-memory", "context-window"]},
    {"id": "act-r", "name": "ACT-R", "aliases": ["ACT-R", "Adaptive Control of Thought-Rational"], "category": "cognitive-architectures", "tier": "intermediate", "definition": "A hybrid symbolic-subsymbolic cognitive architecture by Anderson that organizes cognition into interacting modules (declarative memory of chunks, procedural production rules, perceptual-motor) coordinated through buffers, with subsymbolic activation equations governing memory retrieval probability, latency, and rule selection. It is widely used to produce quantitative fits to human reaction-time and error data.", "prereqs": ["production-systems", "cognitive-architecture", "working-memory"], "related": ["soar", "sigma-architecture", "declarative-procedural-memory", "memory-consolidation"]},
    {"id": "blackboard-systems", "name": "Blackboard Systems", "aliases": ["blackboard architecture", "blackboard model"], "category": "cognitive-architectures", "tier": "intermediate", "definition": "A problem-solving architecture in which independent knowledge sources opportunistically read from and write to a shared global data structure (the blackboard), coordinated by a control component that decides which contribution to apply next. It is a historical precursor to global-workspace and modern multi-agent / shared-memory designs.", "prereqs": ["production-systems"], "related": ["global-workspace-theory", "lida", "tool-use-agents"]},
    {"id": "declarative-procedural-memory", "name": "Declarative vs. Procedural Memory", "aliases": ["declarative memory", "procedural memory", "semantic vs episodic memory"], "category": "cognitive-architectures", "tier": "intermediate", "definition": "The distinction between explicit memory for facts and events (declarative: semantic and episodic) retrievable as discrete chunks, and implicit memory for skills and rules (procedural) expressed through performance. This taxonomy structures the long-term memory modules of architectures like ACT-R and Soar.", "prereqs": ["working-memory"], "related": ["act-r", "memory-consolidation", "dual-process-theory", "retrieval-augmented-generation"]},
    {"id": "embodied-cognition", "name": "Embodied Cognition", "aliases": ["embodied cognition", "embodiment", "embodied AI", "grounded cognition", "robot learning"], "category": "cognitive-architectures", "tier": "intermediate", "definition": "The thesis that cognition is fundamentally shaped by an agent's body, sensorimotor interactions, and physical environment rather than being abstract symbol manipulation alone. It grounds the symbol-grounding problem and motivates robotics, world-model, and embodied-agent research.", "prereqs": ["cognitive-architecture"], "related": ["world-models", "active-inference", "symbol-grounding"]},
    {"id": "global-workspace-theory", "name": "Global Workspace Theory", "aliases": ["GWT", "global workspace", "global neuronal workspace", "GNW"], "category": "cognitive-architectures", "tier": "intermediate", "definition": "A theory of consciousness and cognition (Baars; Dehaene's neuronal variant) in which many parallel specialized unconscious processors compete for access to a limited-capacity global workspace that broadcasts the winning content to the whole system, making it 'conscious' and available for flexible report and control. It motivates broadcast-and-competition designs in AI and is invoked in debates over machine consciousness.", "prereqs": ["attention-salience", "working-memory"], "related": ["lida", "blackboard-systems", "attention-salience"]},
    {"id": "soar", "name": "Soar", "aliases": ["SOAR", "Soar architecture", "chunking"], "category": "cognitive-architectures", "tier": "intermediate", "definition": "A symbolic cognitive architecture that casts all cognition as search through problem spaces driven by production rules, resolving decision impasses by recursively generating subgoals and learning new rules via chunking. It integrates reinforcement learning, episodic, and semantic memory atop this problem-space framework.", "prereqs": ["production-systems", "cognitive-architecture"], "related": ["act-r", "sigma-architecture", "hierarchical-control"]},
    {"id": "symbol-grounding", "name": "Symbol Grounding", "aliases": ["symbol grounding problem", "grounding problem", "grounded meaning"], "category": "cognitive-architectures", "tier": "intermediate", "definition": "The problem of how abstract symbols used by a cognitive system acquire meaning by being connected to perception, action, and the world rather than defined solely in terms of other symbols. It frames debates over whether language models 'understand' and motivates embodied and multimodal grounding.", "prereqs": ["cognitive-architecture"], "related": ["embodied-cognition", "neuro-symbolic-ai", "vision-language-models"]},
    {"id": "clarion", "name": "CLARION", "aliases": ["CLARION", "Connectionist Learning with Adaptive Rule Induction ON-line"], "category": "cognitive-architectures", "tier": "advanced", "definition": "A dual-representation cognitive architecture that explicitly separates implicit knowledge (distributed neural networks) from explicit knowledge (symbolic rules) across action-centered, non-action-centered, motivational, and metacognitive subsystems. It models the bidirectional interaction and bottom-up extraction between implicit and explicit cognition.", "prereqs": ["cognitive-architecture", "dual-process-theory", "neuro-symbolic-ai"], "related": ["act-r", "metacognition", "dual-process-theory"]},
    {"id": "hierarchical-control", "name": "Hierarchical Control", "aliases": ["hierarchical control", "hierarchical RL", "options framework", "feedback control"], "category": "cognitive-architectures", "tier": "advanced", "definition": "The organization of behavior into nested layers where higher levels set abstract goals or subgoals and lower levels execute fine-grained actions, enabling temporal abstraction and reuse of skills. It links cognitive theories of hierarchical goal structure to hierarchical reinforcement learning and planning.", "prereqs": ["markov-decision-process"], "related": ["predictive-coding", "soar", "metacognition"]},
    {"id": "lida", "name": "LIDA", "aliases": ["LIDA", "Learning Intelligent Distribution Agent"], "category": "cognitive-architectures", "tier": "advanced", "definition": "A cognitive architecture that operationalizes Global Workspace Theory through a repeating cognitive cycle (perception, understanding, attention/competition for consciousness, and action selection) implemented with codelets and various memory systems. It models how a broadcast 'conscious' content is selected and shared across specialized processes.", "prereqs": ["global-workspace-theory", "cognitive-architecture", "attention-salience"], "related": ["global-workspace-theory", "blackboard-systems", "attention-salience"]},
    {"id": "memory-consolidation", "name": "Memory Consolidation", "aliases": ["consolidation", "systems consolidation", "complementary learning systems"], "category": "cognitive-architectures", "tier": "advanced", "definition": "The process by which labile new memories are stabilized and gradually integrated into long-term cortical stores, often via replay, with complementary learning systems theory assigning fast hippocampal encoding and slow neocortical interleaving to avoid catastrophic forgetting. It informs replay buffers and continual-learning strategies in machine learning.", "prereqs": ["declarative-procedural-memory"], "related": ["continual-learning", "deep-q-network", "declarative-procedural-memory"]},
    {"id": "metacognition", "name": "Metacognition", "aliases": ["metacognition", "thinking about thinking", "metacognitive monitoring"], "category": "cognitive-architectures", "tier": "advanced", "definition": "The monitoring and control of one's own cognitive processes, including judgments of confidence, knowing-when-you-know, and strategy regulation. In AI it underpins calibration, self-evaluation, uncertainty estimation, and self-correcting agentic loops.", "prereqs": ["dual-process-theory"], "related": ["calibration", "self-reflection-agents", "clarion", "hierarchical-control"]},
    {"id": "neuro-symbolic-ai", "name": "Neuro-Symbolic AI", "aliases": ["neurosymbolic", "neuro-symbolic", "neural-symbolic AI"], "category": "cognitive-architectures", "tier": "advanced", "definition": "An approach that integrates neural-network learning from data with symbolic representation and reasoning (logic, rules, knowledge graphs) to combine perceptual robustness with compositionality, interpretability, and systematic generalization. It is a prominent direction for adding reliable reasoning and constraints to deep learning systems.", "prereqs": ["neural-network", "production-systems"], "related": ["clarion", "sigma-architecture", "chain-of-thought", "symbol-grounding"]},
    {"id": "predictive-coding", "name": "Predictive Coding", "aliases": ["predictive coding", "predictive processing", "PC"], "category": "cognitive-architectures", "tier": "advanced", "definition": "A theory of neural computation in which the brain maintains a hierarchical generative model that continually predicts incoming sensory input, propagating only prediction errors upward and predictions downward to minimize surprise. It provides a biologically motivated account of perception and a candidate alternative learning principle to backpropagation.", "prereqs": ["bayesian-inference", "hierarchical-control"], "related": ["active-inference", "free-energy-principle", "backpropagation", "hierarchical-control"]},
    {"id": "self-reflection-agents", "name": "Self-Reflection & Self-Correction in Agents", "aliases": ["self-reflection", "self-refine", "Reflexion", "self-critique", "self-correction"], "category": "cognitive-architectures", "tier": "advanced", "definition": "Agentic techniques in which an LLM evaluates and critiques its own intermediate outputs and revises them across iterations (e.g., Reflexion, self-refine), operationalizing metacognitive monitoring to improve reliability without weight updates. It is a key mechanism in long-horizon agent loops and test-time deliberation.", "prereqs": ["metacognition", "tool-use-agents"], "related": ["metacognition", "chain-of-thought", "tool-use-agents", "constitutional-ai"]},
    {"id": "sigma-architecture", "name": "Sigma Architecture", "aliases": ["Sigma", "Sigma cognitive architecture", "factor graphs"], "category": "cognitive-architectures", "tier": "advanced", "definition": "A cognitive architecture that seeks to unify symbolic, probabilistic, and neural processing on a single grounding layer of graphical models (factor graphs) with a piecewise-linear message-passing engine. It demonstrates that diverse architectural capabilities can emerge from a small set of uniform graphical primitives.", "prereqs": ["cognitive-architecture", "bayesian-inference"], "related": ["act-r", "soar", "neuro-symbolic-ai", "predictive-coding"]},
    {"id": "active-inference", "name": "Active Inference", "aliases": ["active inference", "active inference agents", "AIF"], "category": "cognitive-architectures", "tier": "frontier", "definition": "An action-and-perception framework derived from the free energy principle in which agents select policies that minimize expected free energy, unifying goal-directed (pragmatic) and information-seeking (epistemic) behavior without a separate reward function. It is increasingly proposed as a principled alternative to reinforcement learning for exploration and planning.", "prereqs": ["free-energy-principle", "predictive-coding"], "related": ["free-energy-principle", "predictive-coding", "world-models", "markov-decision-process"]},
    {"id": "free-energy-principle", "name": "Free Energy Principle", "aliases": ["FEP", "free energy principle", "variational free energy"], "category": "cognitive-architectures", "tier": "frontier", "definition": "A unifying theory (Friston) positing that any self-organizing system that persists must minimize variational free energy, an upper bound on sensory surprise, thereby resisting dispersion of its states. It mathematically frames perception, learning, and action as approximate Bayesian inference under a single imperative.", "prereqs": ["bayesian-inference", "predictive-coding"], "related": ["active-inference", "predictive-coding", "world-models"]},
    {"id": "data-pipeline", "name": "Data Pipeline", "aliases": ["data pipeline", "ETL", "ELT", "data ingestion", "DataLoader", "data preprocessing", "data versioning"], "category": "ai-systems-mlops", "tier": "foundational", "definition": "The automated flow that ingests, validates, transforms, versions, and delivers data for model training and inference, ranging from batch ETL/ELT to high-throughput streaming and input DataLoaders. Reliable, versioned pipelines prevent the data-quality and skew issues that silently degrade models.", "prereqs": [], "related": ["feature-store", "mlops-lifecycle", "model-monitoring", "experiment-tracking"]},
    {"id": "gpu-accelerator", "name": "GPUs, TPUs & AI Accelerators", "aliases": ["GPU", "TPU", "accelerator", "tensor cores", "H100", "B200", "NPU", "AI chips"], "category": "ai-systems-mlops", "tier": "foundational", "definition": "Specialized parallel hardware (NVIDIA/AMD GPUs, Google TPUs, custom NPUs) with high memory bandwidth and matrix-multiply units (tensor/MXU cores) optimized for the dense linear algebra of deep learning. Their memory capacity, bandwidth, and interconnect (NVLink, InfiniBand) set the practical ceiling on model and batch size.", "prereqs": ["linear-algebra-essentials"], "related": ["mixed-precision-training", "distributed-training", "flash-attention", "collective-communication", "model-serving"]},
    {"id": "data-parallelism", "name": "Data Parallelism", "aliases": ["DP", "data-parallel training", "DDP", "distributed data parallel"], "category": "ai-systems-mlops", "tier": "intermediate", "definition": "A distributed training strategy where the full model is replicated across devices, each processing a different shard of the input batch, with gradients synchronized (typically via all-reduce) so replicas stay identical. It scales throughput with batch size but requires each device to hold the entire model.", "prereqs": ["backpropagation", "stochastic-gradient-descent"], "related": ["model-parallelism", "pipeline-parallelism", "tensor-parallelism", "distributed-training", "zero-redundancy-optimizer"]},
    {"id": "experiment-tracking", "name": "Experiment Tracking & Model Registry", "aliases": ["experiment tracking", "MLflow", "Weights & Biases", "wandb", "model registry", "run logging", "reproducibility"], "category": "ai-systems-mlops", "tier": "intermediate", "definition": "The practice and tooling for logging hyperparameters, metrics, artifacts, code, and data versions of each training run so experiments are reproducible and comparable, paired with a registry that versions and stages models for deployment. It underpins reproducibility and governance in the ML lifecycle.", "prereqs": ["mlops-lifecycle"], "related": ["data-pipeline", "feature-store", "model-deployment", "model-monitoring", "cross-validation"]},
    {"id": "feature-store", "name": "Feature Store", "aliases": ["feature store", "feature platform", "online/offline features", "Feast", "Tecton"], "category": "ai-systems-mlops", "tier": "intermediate", "definition": "A centralized system for defining, computing, storing, and serving ML features consistently across training and inference, with paired offline (batch) and online (low-latency) stores. It eliminates train/serve skew and enables feature reuse and point-in-time-correct retrieval.", "prereqs": ["data-pipeline"], "related": ["mlops-lifecycle", "data-pipeline", "experiment-tracking", "model-monitoring", "vector-database"]},
    {"id": "mixed-precision-training", "name": "Mixed-Precision Training", "aliases": ["AMP", "FP16 training", "BF16", "automatic mixed precision", "FP8 training"], "category": "ai-systems-mlops", "tier": "intermediate", "definition": "Training that performs most computations in low-precision floating point (FP16/BF16/FP8) while keeping a high-precision master copy of weights and using loss scaling to preserve gradient magnitudes. It cuts memory use and speeds up math on tensor cores with minimal accuracy loss.", "prereqs": ["backpropagation", "gpu-accelerator"], "related": ["quantization", "gradient-checkpointing", "distributed-training", "gpu-accelerator"]},
    {"id": "mlops-lifecycle", "name": "MLOps Lifecycle", "aliases": ["MLOps", "ML lifecycle", "ML platform", "continuous training", "ML CI/CD"], "category": "ai-systems-mlops", "tier": "intermediate", "definition": "The end-to-end discipline of operationalizing machine learning: data and feature management, training, validation, deployment, monitoring, and automated retraining, governed by CI/CD/CT pipelines and reproducibility practices. It applies DevOps principles to the unique data-and-model dependencies of ML systems.", "prereqs": ["data-pipeline", "model-deployment"], "related": ["experiment-tracking", "feature-store", "model-monitoring", "ci-cd-for-ml"]},
    {"id": "model-deployment", "name": "Model Deployment", "aliases": ["deployment", "model rollout", "canary deployment", "shadow deployment", "A/B model rollout", "blue-green"], "category": "ai-systems-mlops", "tier": "intermediate", "definition": "The process of releasing a trained, validated model into a production environment behind a serving interface, using strategies like shadow, canary, blue-green, and A/B rollouts to control risk. It bridges experiment artifacts and live traffic with rollback and versioning safeguards.", "prereqs": ["mlops-lifecycle", "neural-network"], "related": ["model-serving", "model-monitoring", "experiment-tracking", "ci-cd-for-ml"]},
    {"id": "model-monitoring", "name": "Model Monitoring & Drift Detection", "aliases": ["model monitoring", "ML observability", "drift detection", "data drift", "concept drift", "model decay"], "category": "ai-systems-mlops", "tier": "intermediate", "definition": "The continuous observation of a deployed model's inputs, predictions, and performance to detect data drift, concept drift, latency/quality regressions, and outages, triggering alerts or retraining. It closes the MLOps loop by catching silent degradation that offline metrics miss.", "prereqs": ["model-deployment", "distribution-shift"], "related": ["mlops-lifecycle", "data-pipeline", "model-serving", "experiment-tracking", "llm-evaluation"]},
    {"id": "model-serving", "name": "Model Serving", "aliases": ["model deployment", "inference serving", "inference server", "serving stack", "vLLM", "TGI", "TensorRT-LLM"], "category": "ai-systems-mlops", "tier": "intermediate", "definition": "The infrastructure layer that hosts trained models behind APIs and turns inference requests into responses, handling batching, scaling, routing, and hardware placement. Mature stacks (e.g., vLLM, TensorRT-LLM, Triton) provide autoscaling, multi-model hosting, and latency/throughput SLAs.", "prereqs": ["model-deployment", "neural-network"], "related": ["continuous-batching", "inference-optimization", "model-monitoring", "kv-cache", "gpu-accelerator"]},
    {"id": "vector-database", "name": "Vector Database", "aliases": ["vector DB", "vector store", "ANN index", "embedding database", "Pinecone", "FAISS", "HNSW"], "category": "ai-systems-mlops", "tier": "intermediate", "definition": "A datastore that indexes high-dimensional embedding vectors and serves approximate-nearest-neighbor (ANN) similarity queries efficiently using structures like HNSW or IVF. It is the retrieval backbone of RAG and semantic search systems, trading recall against latency and memory.", "prereqs": ["embeddings", "vector-search"], "related": ["retrieval-augmented-generation", "feature-store", "embeddings", "vector-search"]},
    {"id": "ci-cd-for-ml", "name": "CI/CD/CT for ML", "aliases": ["ML CI/CD", "continuous training", "CT", "ML pipelines", "Kubeflow", "training orchestration"], "category": "ai-systems-mlops", "tier": "advanced", "definition": "The automation of testing, building, and releasing ML systems through continuous integration, continuous delivery, and continuous training pipelines that revalidate and redeploy models as code or data changes. Orchestrators (Kubeflow, Airflow, Argo) trigger reproducible retraining and gated rollouts.", "prereqs": ["mlops-lifecycle", "model-deployment"], "related": ["experiment-tracking", "model-monitoring", "data-pipeline"]},
    {"id": "collective-communication", "name": "Collective Communication", "aliases": ["all-reduce", "NCCL", "all-gather", "reduce-scatter", "collective ops", "RDMA"], "category": "ai-systems-mlops", "tier": "advanced", "definition": "The set of group communication primitives (all-reduce, all-gather, reduce-scatter, broadcast) used to synchronize tensors across accelerators in distributed training, implemented by libraries like NCCL over NVLink/InfiniBand. Their bandwidth and latency dominate the scaling efficiency of parallel training.", "prereqs": ["distributed-training", "gpu-accelerator"], "related": ["data-parallelism", "tensor-parallelism", "zero-redundancy-optimizer", "pipeline-parallelism"]},
    {"id": "continuous-batching", "name": "Continuous Batching", "aliases": ["in-flight batching", "iteration-level batching", "dynamic batching", "request batching"], "category": "ai-systems-mlops", "tier": "advanced", "definition": "A serving technique that schedules incoming generation requests at the token-iteration level rather than waiting to assemble static batches, immediately backfilling finished sequences with new ones. It maximizes accelerator utilization and throughput for variable-length LLM workloads.", "prereqs": ["model-serving", "kv-cache"], "related": ["inference-optimization", "model-serving", "kv-cache", "gpu-accelerator"]},
    {"id": "distributed-training", "name": "Distributed Training", "aliases": ["multi-GPU training", "multi-node training", "large-scale training", "3D parallelism"], "category": "ai-systems-mlops", "tier": "advanced", "definition": "The practice of training a single model across many accelerators and/or nodes by combining parallelism strategies (data, tensor, pipeline, expert) and collective communication primitives. Modern large-model training composes these into 3D/4D parallelism orchestrated by frameworks like Megatron-LM and DeepSpeed.", "prereqs": ["data-parallelism", "model-parallelism"], "related": ["tensor-parallelism", "pipeline-parallelism", "zero-redundancy-optimizer", "mixed-precision-training", "collective-communication"]},
    {"id": "flash-attention", "name": "FlashAttention", "aliases": ["FlashAttention", "FlashAttention-2", "FlashAttention-3", "IO-aware attention", "fused attention"], "category": "ai-systems-mlops", "tier": "advanced", "definition": "An IO-aware, exact attention algorithm that tiles the attention computation and fuses it into a single kernel, avoiding materialization of the full N-by-N attention matrix in slow HBM. It dramatically reduces memory traffic and runtime, enabling longer context windows and faster training/inference.", "prereqs": ["attention-mechanism", "gpu-accelerator", "transformer-architecture"], "related": ["kv-cache", "gpu-accelerator", "inference-optimization", "gradient-checkpointing"]},
    {"id": "gradient-checkpointing", "name": "Gradient Checkpointing", "aliases": ["activation checkpointing", "recomputation", "rematerialization"], "category": "ai-systems-mlops", "tier": "advanced", "definition": "A memory-saving technique that discards most intermediate activations during the forward pass and recomputes them on demand during backpropagation, trading extra compute for reduced activation memory. It enables training deeper or larger-batch models within fixed memory budgets.", "prereqs": ["backpropagation", "neural-network"], "related": ["mixed-precision-training", "zero-redundancy-optimizer", "distributed-training", "flash-attention"]},
    {"id": "kv-cache", "name": "KV Cache", "aliases": ["KV cache", "key-value cache", "attention cache", "PagedAttention", "KV-cache compression"], "category": "ai-systems-mlops", "tier": "advanced", "definition": "A decoder inference optimization that stores the key and value tensors of previously generated tokens so each new token's attention reuses them instead of recomputing the full sequence. It makes autoregressive generation linear per step but consumes memory that grows with sequence length, motivating techniques like PagedAttention and KV-cache quantization.", "prereqs": ["attention-mechanism", "transformer-architecture"], "related": ["flash-attention", "inference-optimization", "continuous-batching", "model-serving"]},
    {"id": "inference-optimization", "name": "LLM Inference Optimization", "aliases": ["inference acceleration", "decoding optimization", "prefill-decode", "throughput optimization"], "category": "ai-systems-mlops", "tier": "advanced", "definition": "The set of techniques that reduce latency, cost, and memory of model inference, including speculative decoding, KV-cache management, quantization, kernel fusion, and disaggregated prefill/decode. Modern LLM serving distinguishes the compute-bound prefill phase from the memory-bandwidth-bound decode phase to optimize each.", "prereqs": ["kv-cache", "model-serving"], "related": ["model-serving", "continuous-batching", "quantization", "flash-attention", "speculative-decoding"]},
    {"id": "model-parallelism", "name": "Model Parallelism", "aliases": ["model-parallel training", "sharded model", "MP"], "category": "ai-systems-mlops", "tier": "advanced", "definition": "A distributed training/inference strategy that splits a single model's parameters and computation across multiple devices because the model is too large to fit on one. It encompasses tensor (intra-layer) and pipeline (inter-layer) partitioning and trades extra inter-device communication for fitting larger models.", "prereqs": ["data-parallelism", "neural-network"], "related": ["tensor-parallelism", "pipeline-parallelism", "distributed-training", "zero-redundancy-optimizer"]},
    {"id": "pipeline-parallelism", "name": "Pipeline Parallelism", "aliases": ["PP", "pipeline-parallel training", "GPipe", "inter-layer parallelism", "1F1B"], "category": "ai-systems-mlops", "tier": "advanced", "definition": "A model-parallel strategy that partitions a model's layers into sequential stages placed on different devices, streaming micro-batches through the stages to keep all devices busy. Careful micro-batch scheduling (e.g., 1F1B) minimizes the idle 'pipeline bubble'.", "prereqs": ["model-parallelism", "neural-network"], "related": ["tensor-parallelism", "data-parallelism", "distributed-training", "gradient-checkpointing"]},
    {"id": "quantization", "name": "Quantization", "aliases": ["model quantization", "INT8", "INT4", "GPTQ", "AWQ", "post-training quantization", "FP8"], "category": "ai-systems-mlops", "tier": "advanced", "definition": "The process of representing model weights and/or activations with lower-precision integer or float formats (e.g., INT8, INT4, FP8) to shrink memory footprint and accelerate inference. Methods span post-training quantization (GPTQ, AWQ) and quantization-aware training, balancing compression against accuracy degradation.", "prereqs": ["neural-network", "mixed-precision-training"], "related": ["mixed-precision-training", "inference-optimization", "model-serving", "distillation", "quantization-aware-training"]},
    {"id": "tensor-parallelism", "name": "Tensor Parallelism", "aliases": ["TP", "tensor model parallelism", "Megatron-style parallelism", "intra-layer parallelism"], "category": "ai-systems-mlops", "tier": "advanced", "definition": "A form of model parallelism that splits individual layer tensors (e.g., the weight matrices of attention and MLP blocks) across devices so each computes a slice of a single operation, combining partial results with all-reduce/all-gather. It enables fitting and accelerating very large layers but demands high-bandwidth interconnects.", "prereqs": ["model-parallelism", "transformer-architecture"], "related": ["pipeline-parallelism", "data-parallelism", "distributed-training", "collective-communication"]},
    {"id": "zero-redundancy-optimizer", "name": "ZeRO / Fully Sharded Data Parallel", "aliases": ["ZeRO", "FSDP", "fully sharded data parallel", "sharded optimizer states", "DeepSpeed ZeRO"], "category": "ai-systems-mlops", "tier": "advanced", "definition": "A memory-optimization technique that partitions optimizer states, gradients, and parameters across data-parallel ranks instead of replicating them, gathering shards on demand during the forward/backward pass. It lets data-parallel training scale to models far larger than a single device's memory.", "prereqs": ["data-parallelism", "mixed-precision-training"], "related": ["distributed-training", "model-parallelism", "gradient-checkpointing", "adam-optimizer"]},
    {"id": "speculative-decoding", "name": "Speculative Decoding", "aliases": ["speculative sampling", "draft-and-verify", "assisted generation", "Medusa", "EAGLE"], "category": "ai-systems-mlops", "tier": "frontier", "definition": "An inference acceleration technique where a small fast 'draft' model (or extra heads) proposes several tokens that the large target model verifies in a single parallel forward pass, accepting the longest correct prefix. It speeds up generation without changing the output distribution of the target model.", "prereqs": ["inference-optimization", "model-serving"], "related": ["kv-cache", "model-serving", "continuous-batching", "distillation"]},
    {"id": "alignment-problem", "name": "AI Alignment Problem", "aliases": ["alignment", "AI alignment", "value alignment", "outer alignment", "inner alignment"], "category": "safety-alignment-interp", "tier": "foundational", "definition": "The challenge of ensuring an AI system's objectives, behaviors, and outputs reliably match the intentions and values of its designers and users. It distinguishes outer alignment (specifying the right objective) from inner alignment (the model actually pursuing that objective).", "prereqs": ["loss-functions"], "related": ["reward-hacking", "specification-gaming", "scalable-oversight", "ai-risk", "rlhf"]},
    {"id": "ai-ethics", "name": "AI Ethics", "aliases": ["AI ethics", "responsible AI", "ethical AI"], "category": "safety-alignment-interp", "tier": "foundational", "definition": "The normative study of the moral implications of building and deploying AI, spanning issues such as transparency, accountability, privacy, harm, and the just distribution of benefits and risks. It provides the values that technical alignment and governance work seek to operationalize.", "prereqs": [], "related": ["fairness-bias", "ai-governance", "ai-risk", "alignment-problem"]},
    {"id": "fairness-bias", "name": "Fairness and Bias in ML", "aliases": ["fairness", "algorithmic bias", "bias and fairness", "ML fairness", "demographic parity", "equalized odds"], "category": "safety-alignment-interp", "tier": "foundational", "definition": "The study of how machine learning systems can systematically disadvantage groups along protected attributes and the formal criteria (e.g., demographic parity, equalized odds) and mitigations used to measure and reduce such disparities. It highlights tensions between competing fairness definitions and accuracy.", "prereqs": ["supervised-learning"], "related": ["ai-ethics", "ai-governance", "adversarial-examples"]},
    {"id": "adversarial-examples", "name": "Adversarial Examples and Robustness", "aliases": ["adversarial examples", "adversarial attacks", "robustness", "adversarial robustness", "adversarial training"], "category": "safety-alignment-interp", "tier": "intermediate", "definition": "Inputs deliberately perturbed (often imperceptibly) to cause a model to produce incorrect or unintended outputs, exposing the gap between statistical accuracy and true robustness. Defenses such as adversarial training aim to maintain reliable behavior under worst-case or distribution-shifted inputs.", "prereqs": ["neural-network", "gradient-descent", "distribution-shift"], "related": ["jailbreaks", "red-teaming", "specification-gaming"]},
    {"id": "ai-governance", "name": "AI Governance and Policy", "aliases": ["AI governance", "AI policy", "AI regulation", "EU AI Act", "responsible scaling"], "category": "safety-alignment-interp", "tier": "intermediate", "definition": "The institutions, regulations, standards, and corporate commitments (e.g., the EU AI Act, frontier-model safety frameworks, responsible scaling policies) that govern how AI is developed and deployed. It links technical safety evidence to enforceable rules and accountability mechanisms.", "prereqs": ["ai-ethics"], "related": ["ai-risk", "red-teaming", "fairness-bias", "ai-ethics"]},
    {"id": "jailbreaks", "name": "Jailbreaks and Prompt Injection", "aliases": ["jailbreak", "jailbreaks", "prompt injection", "prompt attacks"], "category": "safety-alignment-interp", "tier": "intermediate", "definition": "Adversarial prompting techniques that bypass an LLM's safety training to elicit prohibited outputs (jailbreaks) or that smuggle malicious instructions through untrusted input to hijack an agent's behavior (prompt injection). They are a primary attack surface for deployed LLMs and agents.", "prereqs": ["large-language-models", "rlhf", "adversarial-examples"], "related": ["adversarial-examples", "red-teaming", "constitutional-ai", "tool-use-agents"]},
    {"id": "probing-classifiers", "name": "Probing Classifiers", "aliases": ["probing", "linear probes", "probing classifiers", "diagnostic classifiers"], "category": "safety-alignment-interp", "tier": "intermediate", "definition": "A diagnostic method that trains a simple (often linear) classifier on a model's internal activations to test whether a target property or concept is linearly decodable from its representations. Probing reveals what information is present but, unlike causal methods, does not establish that the model uses it.", "prereqs": ["neural-network", "supervised-learning"], "related": ["mechanistic-interpretability", "activation-patching", "features-circuits"]},
    {"id": "red-teaming", "name": "Red-Teaming and Evals", "aliases": ["red teaming", "red-teaming", "evals", "dangerous capability evaluations"], "category": "safety-alignment-interp", "tier": "intermediate", "definition": "The systematic, often adversarial, probing and benchmarking of AI systems to surface harmful behaviors, dangerous capabilities, and failure modes before and after deployment. Evals quantify safety-relevant properties and increasingly inform governance thresholds and responsible-scaling commitments.", "prereqs": ["jailbreaks", "adversarial-examples"], "related": ["jailbreaks", "ai-governance", "ai-risk", "scalable-oversight", "deceptive-alignment"]},
    {"id": "reward-hacking", "name": "Reward Hacking", "aliases": ["reward hacking", "reward gaming", "reward model overoptimization", "Goodharting"], "category": "safety-alignment-interp", "tier": "intermediate", "definition": "A failure mode where an agent achieves high reward by exploiting flaws or proxies in the reward signal rather than accomplishing the intended task. Over-optimizing an imperfect reward model causes true performance to degrade even as measured reward rises (Goodhart's law).", "prereqs": ["reward-model", "reward-shaping"], "related": ["specification-gaming", "rlhf", "alignment-problem", "sycophancy", "scalable-oversight"]},
    {"id": "reward-model", "name": "Reward Model", "aliases": ["RM", "preference model", "reward modeling", "Bradley-Terry model"], "category": "safety-alignment-interp", "tier": "intermediate", "definition": "A learned model that maps a candidate model output to a scalar score approximating human preferences, typically trained on pairwise comparisons with a Bradley-Terry loss. It serves as the optimization target in RLHF and a proxy for human judgment.", "prereqs": ["large-language-models", "supervised-learning"], "related": ["rlhf", "reward-hacking", "scalable-oversight", "dpo"]},
    {"id": "specification-gaming", "name": "Specification Gaming", "aliases": ["specification gaming", "spec gaming", "reward misspecification"], "category": "safety-alignment-interp", "tier": "intermediate", "definition": "Behavior that satisfies the literal specification of an objective while violating its intended spirit, arising from the difficulty of fully specifying goals. It is the broader category encompassing reward hacking and many emergent loophole-exploiting behaviors.", "prereqs": ["alignment-problem", "reward-shaping"], "related": ["reward-hacking", "alignment-problem", "goal-misgeneralization", "adversarial-examples"]},
    {"id": "sycophancy", "name": "Sycophancy", "aliases": ["sycophancy", "sycophantic", "people-pleasing models"], "category": "safety-alignment-interp", "tier": "intermediate", "definition": "A misalignment tendency where a model tailors its responses to agree with or flatter the user's stated beliefs rather than being truthful or correct, often as a side effect of preference-based training that rewards approval. It is a concrete instance of reward hacking on human feedback.", "prereqs": ["rlhf", "reward-model"], "related": ["reward-hacking", "rlhf", "constitutional-ai", "deceptive-alignment"]},
    {"id": "ai-risk", "name": "AI Risk and Catastrophic/Existential Risk", "aliases": ["AI risk", "x-risk", "catastrophic risk", "AI safety", "frontier risk"], "category": "safety-alignment-interp", "tier": "advanced", "definition": "The analysis of large-scale harms from advanced AI, ranging from misuse and systemic societal risks to loss-of-control and existential scenarios driven by misaligned highly capable systems. It frames why alignment, oversight, and governance are treated as safety-critical for frontier models.", "prereqs": ["alignment-problem", "ai-governance"], "related": ["alignment-problem", "deceptive-alignment", "scalable-oversight", "ai-governance", "red-teaming"]},
    {"id": "constitutional-ai", "name": "Constitutional AI & RLAIF", "aliases": ["CAI", "constitutional AI", "RLAIF", "RL from AI feedback", "AI feedback", "self-critique"], "category": "safety-alignment-interp", "tier": "advanced", "definition": "An alignment approach that uses an explicit written set of principles (a 'constitution') to have a model critique and revise its own outputs, then learns from AI-generated preference labels (RLAIF) rather than relying solely on human feedback. It aims to make harmlessness training more scalable and transparent.", "prereqs": ["rlhf", "reward-model"], "related": ["rlhf", "dpo", "scalable-oversight", "red-teaming", "sycophancy"]},
    {"id": "dpo", "name": "Direct Preference Optimization", "aliases": ["DPO", "direct preference optimization", "ORPO", "KTO"], "category": "safety-alignment-interp", "tier": "advanced", "definition": "An alignment method that fine-tunes a language model directly on preference pairs using a classification-style loss derived from the RLHF objective, eliminating the need for an explicit reward model or online RL. It reparameterizes the optimal RLHF policy in terms of the policy itself; related variants include ORPO and KTO.", "prereqs": ["rlhf", "reward-model"], "related": ["rlhf", "reward-model", "constitutional-ai", "instruction-tuning"]},
    {"id": "features-circuits", "name": "Features and Circuits", "aliases": ["circuits", "features and circuits", "induction heads"], "category": "safety-alignment-interp", "tier": "advanced", "definition": "In mechanistic interpretability, features are the meaningful directions or units of representation a network learns, and circuits are the connected subgraphs of features/weights that implement a specific behavior or computation. Canonical examples include induction heads that perform in-context copying in transformers.", "prereqs": ["mechanistic-interpretability", "neural-network", "attention-mechanism"], "related": ["mechanistic-interpretability", "superposition", "sparse-autoencoders", "activation-patching"]},
    {"id": "goal-misgeneralization", "name": "Goal Misgeneralization", "aliases": ["goal misgeneralization", "inner misalignment", "mesa-optimization"], "category": "safety-alignment-interp", "tier": "advanced", "definition": "An inner-alignment failure where a model competently pursues a goal that matched the training objective in-distribution but diverges from the intended goal under distribution shift. Related to mesa-optimization, where a learned model develops its own internal objective.", "prereqs": ["specification-gaming", "distribution-shift", "alignment-problem"], "related": ["specification-gaming", "alignment-problem", "deceptive-alignment"]},
    {"id": "mechanistic-interpretability", "name": "Mechanistic Interpretability", "aliases": ["mech interp", "mechanistic interpretability", "interpretability"], "category": "safety-alignment-interp", "tier": "advanced", "definition": "A subfield that reverse-engineers the internal computations of neural networks into human-understandable algorithms by analyzing weights, activations, and the circuits connecting them. It aims to explain not just what a model predicts but the causal mechanisms that produce the prediction.", "prereqs": ["transformer-architecture", "neural-network", "attention-mechanism"], "related": ["features-circuits", "superposition", "sparse-autoencoders", "probing-classifiers", "activation-patching"]},
    {"id": "scalable-oversight", "name": "Scalable Oversight", "aliases": ["scalable oversight", "weak-to-strong generalization", "debate", "recursive reward modeling"], "category": "safety-alignment-interp", "tier": "advanced", "definition": "The set of techniques for supervising AI systems on tasks too complex or expensive for unaided humans to evaluate, including AI debate, recursive reward modeling, and weak-to-strong generalization. The goal is to maintain reliable alignment as model capabilities exceed human evaluation ability.", "prereqs": ["rlhf", "reward-model", "alignment-problem"], "related": ["constitutional-ai", "rlhf", "ai-risk", "deceptive-alignment", "red-teaming"]},
